SELECT COUNT(*) AS modification_count
FROM address_modifications
WHERE address_id = 0;

SELECT modified_by, COUNT(modification_id) AS total_modifications
FROM address_modifications
GROUP BY modified_by;

SELECT address_id, modified_by, modified_date
FROM address_modifications
WHERE modification_type = 'update';

SELECT COUNT(DISTINCT address_id) AS unique_addresses
FROM address_tags
WHERE tag_name = 'delivery_preferences';

SELECT state_province_name
FROM state_provinces
WHERE state_province_id = 0;

SELECT COUNT(*) AS total_primary_addresses
FROM customer_addresses
WHERE is_primary = 1;

SELECT COUNT(*) 
FROM address_validation_results 
WHERE is_valid = 1;

SELECT is_valid
FROM address_validation_results
WHERE validation_date >= '2023-01-01';

SELECT COUNT(address_id) AS total_addresses_with_delivery_preference
FROM address_tags
WHERE tag_name = 'delivery_preferences';

SELECT customer_id, COUNT(DISTINCT address_type_id) AS total_address_types
FROM customer_addresses
GROUP BY customer_id;

SELECT latitude
FROM addresses
WHERE latitude = (SELECT MAX(latitude) FROM addresses);

SELECT COUNT(version_id) AS version_count
FROM address_versions
WHERE address_id = 1;

SELECT version_comment
FROM address_versions
WHERE version_id = 1;

SELECT COUNT(*) AS active_address_count
FROM address_history
WHERE is_active = 1;
